            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor Feed 补充流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-91"
          },
          "rationale": "诊断直接指出 feed-91 缺少流量规格；在不假定具体数值的前提下添加流量占位可形成最小可审查补丁，并保持在已选中流股范围内。",
          "patch": {
            "spec_placeholders": [
              {
                "path": "specs.flow_rate",
                "value_type": "number",
                "units_hint": "flow rate units per site convention",
                "reason": "required_by_stream_spec_validation"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor 补充出口压力目标占位",
          "target": {
            "type": "unit",
            "id": "compressor-21"
          },
          "rationale": "compressor-21 已配置为 outlet_pressure 控制，但缺少目标值；添加参数占位比推断具体设定值更可审查且不会冒充已完成调参。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "value_type": "number",
                "units_hint": "kPa",
                "reason": "required_by_outlet_pressure_control_mode"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Recycle Compressor 补充最小流量旁路百分比占位",
          "target": {
            "type": "unit",
            "id": "compressor-21"
          },
          "rationale": "anti_surge_review_required 为 true 且诊断指出缺少 minimum flow bypass percent；使用参数占位可直接回应错误并保持变更局部。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.minimum_flow_bypass_percent",
                "value_type": "number",
                "units_hint": "percent",
                "reason": "required_by_anti_surge_review"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-4",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Product Cooler Outlet 91 提供下游去向连接占位",
          "target": {
            "type": "stream",
            "id": "cooler-outlet-91"
          },
          "rationale": "cooler-outlet-91 当前无下游消费者或导出端，导致拓扑无效；但现有证据不足以确定具体连接对象，因此仅建议添加待确认的下游连接占位，不修改 cooler-21 本体或声明已恢复拓扑。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "cooler-outlet-91",
              "missing_endpoint": "downstream_consumer_or_export_sink",
              "allowed_target_types": [
                "unit",
